// Azure Function: SendGrid Email & Twilio SMS Integration
// NOTE: All secrets MUST be stored in Application Settings (environment variables),
// never hardcoded in source code. For production, use Key Vault references.
//
// Required Application Settings (set in Azure Portal > Configuration):
//   SENDGRID_API_KEY - Your SendGrid API key
//   TWILIO_ACCOUNT_SID - Your Twilio Account SID
//   TWILIO_AUTH_TOKEN - Your Twilio Auth Token
//   TWILIO_PHONE_NUMBER - Your Twilio sender phone number
//   SENDGRID_FROM_EMAIL - Verified sender email address
//   ALLOWED_ORIGINS - Comma-separated list of allowed origins (optional)

const { app } = require('@azure/functions');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// Input validation constants
const MAX_SUBJECT_LENGTH = 200;
const MAX_BODY_LENGTH = 5000;
const MAX_PHONE_LENGTH = 20;
const MAX_EMAIL_LENGTH = 254;
const MAX_NAME_LENGTH = 100;

// Strict allowlist for notification types
const ALLOWED_NOTIFICATION_TYPES = new Set(['email', 'sms', 'both']);

// Email validation regex (RFC 5322 simplified)
const EMAIL_REGEX = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;

// E.164 phone number format
const PHONE_REGEX = /^\+[1-9]\d{1,14}$/;

/**
 * Sanitize a string by removing control characters and trimming.
 * Does NOT strip HTML — that is handled by SendGrid's text mode.
 */
function sanitizeString(input, maxLength) {
    if (typeof input !== 'string') {
        return null;
    }
    // Remove control characters except newline and tab
    const cleaned = input.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '').trim();
    if (cleaned.length === 0 || cleaned.length > maxLength) {
        return null;
    }
    return cleaned;
}

/**
 * Strip all HTML tags from a string to prevent injection in plaintext contexts.
 */
function stripHtml(input) {
    if (typeof input !== 'string') return '';
    return input.replace(/<[^>]*>/g, '');
}

/**
 * Validate email address format.
 */
function isValidEmail(email) {
    if (typeof email !== 'string') return false;
    if (email.length > MAX_EMAIL_LENGTH) return false;
    return EMAIL_REGEX.test(email);
}

/**
 * Validate phone number in E.164 format.
 */
function isValidPhone(phone) {
    if (typeof phone !== 'string') return false;
    if (phone.length > MAX_PHONE_LENGTH) return false;
    return PHONE_REGEX.test(phone);
}

/**
 * Retrieve a required secret from environment variables.
 * Throws if not configured — never falls back to hardcoded values.
 */
function getRequiredSecret(name) {
    const value = process.env[name];
    if (!value || value.trim().length === 0) {
        throw new Error(`Required configuration '${name}' is not set. Configure it in Application Settings.`);
    }
    return value.trim();
}

/**
 * Send email via SendGrid.
 */
async function sendEmail(toEmail, toName, subject, body) {
    const apiKey = getRequiredSecret('SENDGRID_API_KEY');
    const fromEmail = getRequiredSecret('SENDGRID_FROM_EMAIL');

    sgMail.setApiKey(apiKey);

    const msg = {
        to: {
            email: toEmail,
            name: toName || undefined,
        },
        from: {
            email: fromEmail,
            name: 'Notification Service',
        },
        subject: subject,
        // Use plaintext only to avoid HTML injection risks
        text: stripHtml(body),
        // Disable tracking to minimize data exposure
        trackingSettings: {
            clickTracking: { enable: false },
            openTracking: { enable: false },
        },
    };

    await sgMail.send(msg);
    return { channel: 'email', status: 'sent', recipient: toEmail };
}

/**
 * Send SMS via Twilio.
 */
async function sendSms(toPhone, body) {
    const accountSid = getRequiredSecret('TWILIO_ACCOUNT_SID');
    const authToken = getRequiredSecret('TWILIO_AUTH_TOKEN');
    const fromPhone = getRequiredSecret('TWILIO_PHONE_NUMBER');

    const client = twilio(accountSid, authToken);

    // Strip HTML and truncate for SMS
    const smsBody = stripHtml(body).substring(0, 1600);

    const message = await client.messages.create({
        body: smsBody,
        from: fromPhone,
        to: toPhone,
    });

    return {
        channel: 'sms',
        status: 'sent',
        recipient: toPhone,
        messageSid: message.sid,
    };
}

/**
 * Main Azure Function handler for sending notifications.
 */
app.http('sendNotification', {
    methods: ['POST'],
    authLevel: 'function', // Requires function key for authentication
    handler: async (request, context) => {
        const requestId = context.invocationId;

        try {
            // Validate Content-Type
            const contentType = request.headers.get('content-type') || '';
            if (!contentType.includes('application/json')) {
                return {
                    status: 400,
                    headers: {
                        'Content-Type': 'application/json',
                        'X-Content-Type-Options': 'nosniff',
                        'X-Frame-Options': 'DENY',
                        'Cache-Control': 'no-store',
                    },
                    jsonBody: {
                        error: 'Content-Type must be application/json',
                        requestId,
                    },
                };
            }

            // Parse request body with size limit check
            let body;
            try {
                const rawBody = await request.text();
                if (rawBody.length > 10000) {
                    return {
                        status: 413,
                        headers: {
                            'Content-Type': 'application/json',
                            'X-Content-Type-Options': 'nosniff',
                        },
                        jsonBody: { error: 'Request body too large', requestId },
                    };
                }
                body = JSON.parse(rawBody);
            } catch {
                return {
                    status: 400,
                    headers: {
                        'Content-Type': 'application/json',
                        'X-Content-Type-Options': 'nosniff',
                    },
                    jsonBody: { error: 'Invalid JSON in request body', requestId },
                };
            }

            // Validate notification type against strict allowlist
            const notificationType = body.type;
            if (!notificationType || !ALLOWED_NOTIFICATION_TYPES.has(notificationType)) {
                return {
                    status: 400,
                    headers: {
                        'Content-Type': 'application/json',
                        'X-Content-Type-Options': 'nosniff',
                    },
                    jsonBody: {
                        error: `Invalid notification type. Allowed: ${[...ALLOWED_NOTIFICATION_TYPES].join(', ')}`,
                        requestId,
                    },
                };
            }

            const results = [];
            const errors = [];

            // Process email notification
            if (notificationType === 'email' || notificationType === 'both') {
                const toEmail = sanitizeString(body.email, MAX_EMAIL_LENGTH);
                if (!toEmail || !isValidEmail(toEmail)) {
                    errors.push({
                        channel: 'email',
                        error: 'Invalid or missing email address',
                    });
                } else {
                    const subject = sanitizeString(body.subject, MAX_SUBJECT_LENGTH);
                    if (!subject) {
                        errors.push({
                            channel: 'email',
                            error: `Subject is required and must be 1-${MAX_SUBJECT_LENGTH} characters`,
                        });
                    } else {
                        const messageBody = sanitizeString(body.message, MAX_BODY_LENGTH);
                        if (!messageBody) {
                            errors.push({
                                channel: 'email',
                                error: `Message is required and must be 1-${MAX_BODY_LENGTH} characters`,
                            });
                        } else {
                            const toName = body.name
                                ? sanitizeString(body.name, MAX_NAME_LENGTH)
                                : null;

                            try {
                                const result = await sendEmail(toEmail, toName, subject, messageBody);
                                results.push(result);
                                // Log success without PII
                                context.log(`Email sent successfully. RequestId: ${requestId}`);
                            } catch (err) {
                                // Log error without exposing secrets or full PII
                                context.error(`Email send failed. RequestId: ${requestId}, Error: ${err.message}`);
                                errors.push({
                                    channel: 'email',
                                    error: 'Failed to send email. Please try again later.',
                                });
                            }
                        }
                    }
                }
            }

            // Process SMS notification
            if (notificationType === 'sms' || notificationType === 'both') {
                const toPhone = sanitizeString(body.phone, MAX_PHONE_LENGTH);
                if (!toPhone || !isValidPhone(toPhone)) {
                    errors.push({
                        channel: 'sms',
                        error: 'Invalid or missing phone number. Must be in E.164 format (e.g., +14155551234)',
                    });
                } else {
                    const messageBody = sanitizeString(body.message, MAX_BODY_LENGTH);
                    if (!messageBody) {
                        errors.push({
                            channel: 'sms',
                            error: `Message is required and must be 1-${MAX_BODY_LENGTH} characters`,
                        });
                    } else {
                        try {
                            const result = await sendSms(toPhone, messageBody);
                            results.push(result);
                            // Log success without PII
                            context.log(`SMS sent successfully. RequestId: ${requestId}`);
                        } catch (err) {
                            // Log error without exposing secrets or full PII
                            context.error(`SMS send failed. RequestId: ${requestId}, Error: ${err.message}`);
                            errors.push({
                                channel: 'sms',
                                error: 'Failed to send SMS. Please try again later.',
                            });
                        }
                    }
                }
            }

            // Determine overall status
            const hasResults = results.length > 0;
            const hasErrors = errors.length > 0;

            let status;
            if (hasResults && !hasErrors) {
                status = 200;
            } else if (hasResults && hasErrors) {
                status = 207; // Multi-Status: partial success
            } else {
                status = 400;
            }

            return {
                status,
                headers: {
                    'Content-Type': 'application/json',
                    'X-Content-Type-Options': 'nosniff',
                    'X-Frame-Options': 'DENY',
                    'Cache-Control': 'no-store',
                    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
                },
                jsonBody: {
                    requestId,
                    results,
                    errors: hasErrors ? errors : undefined,
                },
            };
        } catch (err) {
            // Catch-all for unexpected errors — never expose internal details
            context.error(`Unexpected error. RequestId: ${requestId}, Error: ${err.message}`);
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json',
                    'X-Content-Type-Options': 'nosniff',
                    'Cache-Control': 'no-store',
                },
                jsonBody: {
                    error: 'An internal error occurred. Please try again later.',
                    requestId,
                },
            };
        }
    },
});

